def analyze_sentiment(text: str) -> float:
    # Simple sentiment scoring with basic emotional valence
    positive_words = ['happy', 'good', 'great', 'excellent', 'love']
    negative_words = ['sad', 'bad', 'terrible', 'awful', 'hate']
    
    text_lower = text.lower()
    
    positive_count = sum(1 for word in positive_words if word in text_lower)
    negative_count = sum(1 for word in negative_words if word in text_lower)
    
    # Normalized sentiment score between -1 and 1
    return (positive_count - negative_count) / (positive_count + negative_count + 1)

def extract_emotional_keywords(text: str) -> list:
    # Extract emotionally charged keywords
    emotion_patterns = {
        'joy': r'\b(happy|excited|delighted|joy)\b',
        'sadness': r'\b(sad|depressed|unhappy|grief)\b', 
        'anger': r'\b(angry|frustrated|furious|mad)\b',
        'fear': r'\b(scared|afraid|worried|anxious)\b'
    }
    
    found_emotions = []
    for emotion, pattern in emotion_patterns.items():
        if re.search(pattern, text.lower()):
            found_emotions.append(emotion)
    
    return found_emotions